mapper.select:
/** EvlTableDao.selectList */ select evl_table_id , evl_table_nm , evl_mthd_cd , fn_cmm_get_code_nm('EVL_MTHD',evl_mthd_cd) as evl_mthd_nm , indvdlz_opinion_writng , case when indvdlz_opinion_writng = true then '작성' when indvdlz_opinion_writng = false then '작성안함' else '-' end as indvdlz_opinion_writng_nm , enabled , case when enabled = true then '사용' when enabled = false then '사용안함' else '-' end as enabled_nm , to_char(created_dt,'yyyy-mm-dd') as rgsde , row_number() over (order by created_dt desc) as rn , creator_id , created_dt , updater_id , updated_dt from uspt_evl_table where 1=1
and enabled = #{enabled}
and evl_mthd_cd = #{evlMthdCd}
and evl_table_nm like '%' || #{evlTableNm} || '%'
offset #{beginRowNum} -1 limit #{itemsPerPage}

	/** EvlTableDao.selectListCount */
	select count(evl_table_id) as cnt
	  from uspt_evl_table
 	 where 1 = 1

			and enabled = #{enabled}


			and evl_mthd_cd = #{evlMthdCd}


			and evl_table_nm like '%' || #{evlTableNm} || '%'

mapper.insert:
/** EvlTableDao.insert */
insert into uspt_evl_table
(
	   evl_table_id
	 , evl_table_nm
	 , evl_mthd_cd
	 , indvdlz_opinion_writng
	 , enabled
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values
    (
	   #{evlTableId}
	 , #{evlTableNm}
	 , #{evlMthdCd}
	 , #{indvdlzOpinionWritng}
	 , true
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.update:
/** EvlTableDao.update */
update uspt_evl_table
   set
	   evl_table_nm              = #{evlTableNm}
	 , evl_mthd_cd               = #{evlMthdCd}
	 , indvdlz_opinion_writng    = #{indvdlzOpinionWritng}
	 , enabled                   = #{enabled}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
 where
	   evl_table_id = #{evlTableId}
